1	// --- Rates, fees, and thresholds ---
2	const PROCESSING_FEE = 5;
3	const FIRST_INSURANCE_RATE = 0.1;
4	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
5	const LOYALTY_RATE = 0.2;
6	const LOYALTY_THRESHOLD_YEARS = 2;
7	const CURSE_RATE = 0.5;
8	const HIGH_ENCHANTMENT_RATE = 0.3;
9	const HIGH_ENCHANTMENT_THRESHOLD = 5;
10	const BLOCK_SIZE = 3;
11	const BLOCK_BASE_PREMIUM = 60;
12	const DEDUCTIBLE = 100;
13	const CAP_MULTIPLIER = 2;
14	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
15	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
16	
17	// --- Item catalog ---
18	const BASE_PREMIUM: Record<string, number> = {
19	  sword: 100,
20	  amulet: 60,
21	  staff: 80,
22	  potion: 40,
23	  rune: 25,
24	  moonstone: 25,
25	};
26	
27	const INSURANCE_VALUE: Record<string, number> = {
28	  sword: 1000,
29	  amulet: 600,
30	  staff: 800,
31	  potion: 400,
32	  rune: 250,
33	  moonstone: 250,
34	};
35	
36	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
37	
38	// --- Domain types ---
39	type Customer = { yearsWithMHPCO: number };
40	type Item = { type: string; cursed?: boolean; enchantment?: number; material?: string };
41	type QuoteStep = { op: "quote"; items: Item[] };
42	type Damage = { itemType: string; amount: number };
43	type Incident = { cause: string; damages: Damage[] };
44	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
45	type Step = QuoteStep | ClaimStep;
46	type Input = { customer: Customer; steps: Step[] };
47	type QuoteResult = { premium: number };
48	type ClaimResult = { payout: number; remainingCap: number };
49	type StepResult = QuoteResult | ClaimResult;
50	
51	const countBy = <T>(items: T[], keyOf: (item: T) => string): Map<string, number> => {
52	  const counts = new Map<string, number>();
53	  for (const item of items) {
54	    const key = keyOf(item);
55	    counts.set(key, (counts.get(key) ?? 0) + 1);
56	  }
57	  return counts;
58	};
59	
60	const countByType = (items: Item[]): Map<string, number> =>
61	  countBy(items, (item) => item.type);
62	
63	const basePremiumForType = (type: string, count: number): number => {
64	  const unit = BASE_PREMIUM[type];
65	  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
66	    return BLOCK_BASE_PREMIUM;
67	  }
68	  return unit * count;
69	};
70	
71	const basePremium = (items: Item[]): number =>
72	  Array.from(countByType(items)).reduce(
73	    (total, [type, count]) => total + basePremiumForType(type, count),
74	    0,
75	  );
76	
77	// MHPCO always rounds in its own favor: premiums up (collect more),
78	// payouts down (pay less).
79	const roundUpInMHPCOFavor = (amount: number): number => Math.ceil(amount);
80	const roundDownInMHPCOFavor = (amount: number): number => Math.floor(amount);
81	
82	const isCursed = (item: Item): boolean => item.cursed === true;
83	const isHighlyEnchanted = (item: Item): boolean =>
84	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
85	
86	const itemSurcharge = (item: Item): number => {
87	  const unit = BASE_PREMIUM[item.type];
88	  const curseSurcharge = isCursed(item) ? unit * CURSE_RATE : 0;
89	  const enchantmentSurcharge = isHighlyEnchanted(item)
90	    ? unit * HIGH_ENCHANTMENT_RATE
91	    : 0;
92	  return curseSurcharge + enchantmentSurcharge;
93	};
94	
95	const sumItemSurcharges = (items: Item[]): number =>
96	  items.reduce((total, item) => total + itemSurcharge(item), 0);
97	
98	const isLoyalCustomer = (customer: Customer): boolean =>
99	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
100	
101	const loyaltyDiscount = (base: number, customer: Customer): number =>
102	  isLoyalCustomer(customer) ? base * LOYALTY_RATE : 0;
103	
104	const firstInsuranceSurcharge = (base: number): number =>
105	  base * FIRST_INSURANCE_RATE;
106	
107	const followUpDiscount = (base: number, stepIndex: number): number =>
108	  stepIndex > 0 ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
109	
110	const quotePremium = (
111	  { items }: QuoteStep,
112	  customer: Customer,
113	  stepIndex: number,
114	): QuoteResult => {
115	  for (const item of items) {
116	    if (!(item.type in BASE_PREMIUM)) {
117	      throw new Error(`Unknown item type "${item.type}"`);
118	    }
119	  }
120	  const base = basePremium(items);
121	  const premium =
122	    base +
123	    sumItemSurcharges(items) +
124	    firstInsuranceSurcharge(base) -
125	    loyaltyDiscount(base, customer) -
126	    followUpDiscount(base, stepIndex) +
127	    PROCESSING_FEE;
128	  return { premium: roundUpInMHPCOFavor(premium) };
129	};
130	
131	const insuranceSum = (items: Item[]): number =>
132	  items.reduce((total, item) => total + INSURANCE_VALUE[item.type], 0);
133	
134	const policyCap = (items: Item[]): number =>
135	  CAP_MULTIPLIER * insuranceSum(items);
136	
137	const triggersHighEnchantmentClause = (item: Item): boolean =>
138	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
139	
140	const reimbursableAmount = (item: Item, amount: number): number =>
141	  triggersHighEnchantmentClause(item)
142	    ? amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE
143	    : amount;
144	
145	const damagePayout = (damage: Damage, items: Item[]): number => {
146	  const item = items.find((i) => i.type === damage.itemType)!;
147	  return Math.max(reimbursableAmount(item, damage.amount) - DEDUCTIBLE, 0);
148	};
149	
150	const totalPayout = (damages: Damage[], items: Item[]): number =>
151	  damages.reduce((total, damage) => total + damagePayout(damage, items), 0);
152	
153	const remainingCapFor = (
154	  policy: number,
155	  items: Item[],
156	  remainingCaps: Map<number, number>,
157	): number => remainingCaps.get(policy) ?? policyCap(items);
158	
159	const validateDamageCounts = (damages: Damage[], items: Item[]): void => {
160	  const itemCounts = countByType(items);
161	  const damageCounts = countBy(damages, (d) => d.itemType);
162	  for (const [type, damageCount] of damageCounts) {
163	    const policyCount = itemCounts.get(type) ?? 0;
164	    if (damageCount > policyCount) {
165	      throw new Error(
166	        `Claim references ${damageCount} damages of type "${type}" but policy covers only ${policyCount}`,
167	      );
168	    }
169	  }
170	};
171	
172	const processClaim = (
173	  step: ClaimStep,
174	  steps: Step[],
175	  remainingCaps: Map<number, number>,
176	): ClaimResult => {
177	  const { items } = steps[step.policy] as QuoteStep;
178	  validateDamageCounts(step.incident.damages, items);
179	  const desired = totalPayout(step.incident.damages, items);
180	  const available = remainingCapFor(step.policy, items, remainingCaps);
181	  const payout = roundDownInMHPCOFavor(Math.min(desired, available));
182	  const remainingCap = available - payout;
183	  remainingCaps.set(step.policy, remainingCap);
184	  return { payout, remainingCap };
185	};
186	
187	const processStep = (
188	  step: Step,
189	  index: number,
190	  steps: Step[],
191	  customer: Customer,
192	  remainingCaps: Map<number, number>,
193	): StepResult =>
194	  step.op === "quote"
195	    ? quotePremium(step, customer, index)
196	    : processClaim(step, steps, remainingCaps);
197	
198	export const run = (input: Input): { results: StepResult[] } => {
199	  const remainingCaps = new Map<number, number>();
200	  return {
201	    results: input.steps.map((step, index) =>
202	      processStep(step, index, input.steps, input.customer, remainingCaps),
203	    ),
204	  };
205	};
